<?php const THIS_PAGE='external_videos'; require_once dirname(__FILE__,2).'/includes/admin_config.php'; require dirname(__FILE__,3).'/custom/external_videos/lib/external_videos_lib.php'; $msg='';$err=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $a=$_POST['action']??''; if($a==='import'){[$ok,$res]=ev_upsert(ev_import_metadata(trim($_POST['source_url']??''))); $ok?$msg='Imported pending ID '.$res:$err=$res;} if($a==='save'){[$ok,$res]=ev_upsert($_POST);$ok?$msg='Saved ID '.$res:$err=$res;} if($a==='bulk'&&!empty($_POST['ids'])){$st=in_array($_POST['bulk_status']??'', ['published','pending','rejected','broken','removed'],true)?$_POST['bulk_status']:'pending';$ids=array_map('intval',$_POST['ids']);ev_db()->query("UPDATE cb_external_videos SET status='".ev_db()->real_escape_string($st)."' WHERE id IN (".implode(',',$ids).")");$msg='Bulk updated';} if($a==='delete'&&!empty($_POST['id'])){ev_db()->query('DELETE FROM cb_external_videos WHERE id='.(int)$_POST['id']);$msg='Deleted';}} $edit=null;if(!empty($_GET['edit']))$edit=ev_db()->query('SELECT * FROM cb_external_videos WHERE id='.(int)$_GET['edit'])->fetch_assoc(); $items=ev_list(['q'=>$_GET['q']??'','status'=>$_GET['status']??'','provider'=>$_GET['provider']??'','limit'=>100]); ?><!doctype html><html><head><meta charset="utf-8"><title>External Videos</title><style>body{font-family:Arial;margin:24px;background:#f6f6f6}.box,table{background:#fff;border:1px solid #ddd}table{width:100%;border-collapse:collapse}td,th{padding:8px;border:1px solid #ddd;text-align:left}.box{padding:16px;margin-bottom:16px}input,textarea,select{width:100%;box-sizing:border-box;margin:4px 0 10px;padding:8px}.btn{padding:8px 12px;background:#333;color:#fff;border:0}.msg{background:#e6ffed;padding:10px}.err{background:#ffecec;padding:10px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:16px}iframe{width:360px;max-width:100%;aspect-ratio:16/9}</style></head><body><h1>External Videos</h1><p><a href="/admin_area/">Admin Home</a> · <a href="/external_feed.php" target="_blank">Frontend Feed</a></p><?php if($msg):?><div class="msg"><?=ev_h($msg)?></div><?php endif;?><?php if($err):?><div class="err"><?=ev_h($err)?></div><?php endif;?><div class="grid"><div class="box"><h2>Import URL</h2><form method="post"><input type="hidden" name="action" value="import"><input name="source_url" required placeholder="https://www.youtube.com/watch?v=..."><button class="btn">Import as Pending</button></form></div><div class="box"><h2><?= $edit?'Edit':'Add' ?></h2><form method="post"><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=ev_h($edit['id']??'')?>"><input name="title" required placeholder="Title" value="<?=ev_h($edit['title']??'')?>"><input name="slug" placeholder="Slug" value="<?=ev_h($edit['slug']??'')?>"><textarea name="description" placeholder="Description"><?=ev_h($edit['description']??'')?></textarea><input name="thumbnail_url" placeholder="Thumbnail URL" value="<?=ev_h($edit['thumbnail_url']??'')?>"><input name="source_url" required placeholder="Source URL" value="<?=ev_h($edit['source_url']??'')?>"><input name="embed_url" required placeholder="Embed URL" value="<?=ev_h($edit['embed_url']??'')?>"><input name="provider" placeholder="Provider" value="<?=ev_h($edit['provider']??'')?>"><input name="author" placeholder="Author" value="<?=ev_h($edit['author']??'')?>"><input name="duration" placeholder="Duration seconds" value="<?=ev_h($edit['duration']??'')?>"><input name="tags" placeholder="tags, comma, separated" value="<?=ev_h($edit['tags']??'')?>"><input name="category_id" placeholder="Category ID" value="<?=ev_h($edit['category_id']??'')?>"><select name="status"><?php foreach(['pending','published','rejected','broken','removed'] as $s):?><option value="<?=$s?>" <?=($edit['status']??'pending')===$s?'selected':''?>><?=$s?></option><?php endforeach;?></select><label><input type="checkbox" name="is_18_plus" value="1" <?=($edit['is_18_plus']??1)?'checked':''?> style="width:auto"> 18+</label><textarea name="source_license" placeholder="source_license / authorization note"><?=ev_h($edit['source_license']??'')?></textarea><textarea name="review_note" placeholder="review note"><?=ev_h($edit['review_note']??'')?></textarea><?php if($edit)echo ev_iframe($edit);?><button class="btn">Save</button></form></div></div><form method="get" class="box"><input name="q" placeholder="search" value="<?=ev_h($_GET['q']??'')?>"><select name="status"><option value="">all status</option><?php foreach(['pending','published','rejected','broken','removed'] as $s):?><option value="<?=$s?>" <?=($_GET['status']??'')===$s?'selected':''?>><?=$s?></option><?php endforeach;?></select><input name="provider" placeholder="provider" value="<?=ev_h($_GET['provider']??'')?>"><button class="btn">Filter</button></form><form method="post"><input type="hidden" name="action" value="bulk"><select name="bulk_status"><option>published</option><option>pending</option><option>rejected</option><option>broken</option><option>removed</option></select><button class="btn">Bulk update</button><table><tr><th></th><th>ID</th><th>Title</th><th>Status</th><th>Provider</th><th>Source</th><th>License</th><th>Actions</th></tr><?php foreach($items as $v):?><tr><td><input type="checkbox" name="ids[]" value="<?=$v['id']?>"></td><td><?=$v['id']?></td><td><?=ev_h($v['title'])?></td><td><?=ev_h($v['status'])?></td><td><?=ev_h($v['provider'])?></td><td><a target="_blank" href="<?=ev_h($v['source_url'])?>">source</a></td><td><?=ev_h(mb_substr($v['source_license']??'',0,80))?></td><td><a href="?edit=<?=$v['id']?>">edit</a> · <a target="_blank" href="/external_video.php?slug=<?=rawurlencode($v['slug'])?>">view</a></td></tr><?php endforeach;?></table></form></body></html>
